import "./EmployeeDetails.css";
import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

function EmployeeDetails() {
  const navigate = useNavigate();
  const [employees, setEmployees] = useState([]);

  // Load employees from localStorage
  useEffect(() => {
    const storedEmployees =
      JSON.parse(localStorage.getItem("employees")) || [];
    setEmployees(storedEmployees);
  }, []);

  return (
    <div className="employee-page">
      {/* Header */}
      <div className="employee-header">
        <h2>Manage Employees</h2>

        <button
          className="add-btn"
          onClick={() => navigate("/dashboard/employee-details/add")}
        >
          Add New Employee
        </button>
      </div>

      {/* Search */}
      <input
        type="text"
        placeholder="Search By Employee ID"
        className="search-box"
      />

      {/* Employee Table */}
      <table className="employee-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Name</th>
            <th>DOB</th>
            <th>Department</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {employees.length > 0 ? (
            employees.map((emp, index) => (
              <tr key={emp.id}>
                <td>{index + 1}</td>
                <td>{emp.name}</td>
                <td>{emp.dob}</td>
                <td>{emp.department}</td>

                <td className="actions">
                  {/* View */}
                  <button
                    className="view"
                    onClick={() =>
                      navigate(`/dashboard/employee-details/view/${emp.id}`)
                    }
                  >
                    View
                  </button>

                  {/* Edit */}
                  <button
                    className="edit"
                    onClick={() =>
                      navigate(`/dashboard/employee-details/edit/${emp.id}`)
                    }
                  >
                    Edit
                  </button>

                  {/* ✅ FIXED SALARY BUTTON */}
                  <button
                    className="salary"
                    onClick={() =>
                      navigate("/dashboard/salary", {
                        state: {
                          employee: emp,
                        },
                      })
                    }
                  >
                    Salary
                  </button>

                  {/* Leave */}
                  <button className="leave">Leave</button>
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" style={{ textAlign: "center" }}>
                No Employees Found
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default EmployeeDetails;
